// ══════════════════════════════ TYPES ═══════════════════════════════════════

export type Layer = "client" | "core" | "edge" | "persistence" | "external" | "planned";
export type Severity = "critical" | "high" | "medium" | "low" | "info";
export type Verdict = "safe" | "watch" | "at-risk";
export type Sensitivity = "secret" | "pii" | "internal" | "public";

export interface SystemNode {
  id: string;
  label: string;
  layer: Layer;
  tech: string;
  verdict: Verdict;
  summary: string;
  detail: string;
  paths: string[];
  owns: string[];
  concerns: string[];
  planned?: boolean;
  x: number;
  y: number;
}

export interface SystemEdge {
  id: string;
  from: string;
  to: string;
  label: string;
  protocol: string;
  carries: string[];
  encrypted: boolean;
  authenticated: boolean;
  detail: string;
  planned?: boolean;
}

export interface DataAsset {
  id: string;
  name: string;
  sensitivity: Sensitivity;
  shape: string;
  storedIn: { nodeId: string; medium: string; table?: string; ttl?: string }[];
  flowsThrough: string[];
  rls?: "full" | "partial" | "none" | "n/a";
  notes: string;
}

export interface ApiRoute {
  id: string;
  method: "GET" | "POST" | "PUT" | "PATCH" | "DELETE" | "WS" | "SSE";
  path: string;
  nodeId: string;
  upstream?: string;
  auth: string;
  reads: string[];
  writes: string[];
  verdict: Verdict;
  notes: string;
}

export interface Finding {
  id: string;
  title: string;
  severity: Severity;
  nodeIds: string[];
  assetIds: string[];
  risk: string;
  evidence: string;
  fix: string;
  effort: "hours" | "days" | "week+";
  status: "open" | "mitigated" | "accepted";
}

export interface ScenarioImpact {
  nodeId: string;
  change: "added" | "removed" | "rewired" | "modified" | "unchanged";
  note: string;
  files: string[];
}

export interface Scenario {
  id: string;
  title: string;
  swap: { from: string; to: string };
  question: string;
  verdictDelta: { security: number; performance: number; complexity: number; cost: number };
  narrative: string;
  retrieval: { source: string; insight: string }[];
  impacts: ScenarioImpact[];
  apisAffected: string[];
  assetsAffected: string[];
  migration: string[];
  effort: "hours" | "days" | "week+" | "multi-week";
  recommended: boolean;
}

export interface Manifest {
  project: string;
  generatedAt: string;
  generatedBy: string;
  nodes: SystemNode[];
  edges: SystemEdge[];
  assets: DataAsset[];
  apis: ApiRoute[];
  findings: Finding[];
  scenarios: Scenario[];
}

